 40→function screenToModel(screenX, screenY, viewport, svgRect) {
 41→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 42→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 43→  return { x, y };
 44→}
