37→        dispatch,
38→        editorDispatch,
39→        project,
40→        getFloor: (...args) => getFloorRef.current(...args),
41→        activeFloorId,
42→        viewport,
43→        snapEnabled,
44→        viewMode,
45→      });
46→    }
47→
48→    if (viewMode !== 'plan') {
49→      return createReadOnlyHandler();
50→    }
51→
52→    const ctx = {
53→      dispatch, editorDispatch,
54→      getFloor: (...args) => getFloorRef.current(...args),
55→      activeFloorId, viewport, snapEnabled,
56→    };
